/**
 * ChatRoom Component
 * 
 * Displays a chat room with messages fetched from the blockchain.
 * Uses getContract() to fetch room data and messages safely.
 */

import React, { useState, useRef, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getContractReadOnly } from '../utils/contract';
import { useWallet } from '../contexts/WalletContext';
import { 
  Send, 
  ArrowLeft, 
  Users, 
  Hash,
  Loader,
  AlertCircle,
  Lock,
  Globe
} from 'lucide-react';

const ChatRoom = () => {
  const { roomId } = useParams();
  const { walletAddress } = useWallet();
  
  // State management
  const [room, setRoom] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef(null);

  /**
   * Format wallet address to short version
   */
  const formatAddress = (address) => {
    if (!address) return '';
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  /**
   * Format timestamp to readable time
   */
  const formatTime = (timestamp) => {
    try {
      const date = new Date(Number(timestamp) * 1000);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch {
      return '';
    }
  };

  /**
   * Format date
   */
  const formatDate = (timestamp) => {
    try {
      const date = new Date(Number(timestamp) * 1000);
      return date.toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric'
      });
    } catch {
      return 'Unknown';
    }
  };

  /**
   * Check if message is from current user
   */
  const isOwnMessage = (sender) => {
    return walletAddress && sender?.toLowerCase() === walletAddress.toLowerCase();
  };

  /**
   * Scroll to bottom of messages
   */
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  /**
   * Fetch room data and messages from blockchain
   */
  const fetchRoomData = async () => {
    if (!roomId) {
      setError('Room ID is required');
      setLoading(false);
      return;
    }

    setLoading(true);
    setError(null);

    try {
      console.log('📥 Fetching room data for room ID:', roomId);

      // Get contract instance
      const contract = await getContractReadOnly();

      // Fetch room details
      const roomData = await contract.getRoom(roomId);
      
      console.log('📊 Raw room data from blockchain:', roomData);

      // Check if room exists
      if (!roomData?.exists) {
        setError('Room not found');
        setLoading(false);
        return;
      }

      // Transform room data safely
      const transformedRoom = {
        id: Number(roomData.id || roomId),
        name: roomData.name || 'Unnamed Room',
        creator: roomData.creator || '',
        isPrivate: roomData.isPrivate || false,
        createdAt: Number(roomData.createdAt || 0),
        exists: roomData.exists || false
      };

      setRoom(transformedRoom);
      console.log('✅ Room data processed:', transformedRoom);

      // Fetch messages for this room
      try {
        const roomMessages = await contract.getMessages(roomId);
        
        console.log('📊 Raw messages from blockchain:', roomMessages?.length || 0);

        // Transform messages safely
        const transformedMessages = (roomMessages || []).map((msg, index) => ({
          id: index,
          sender: msg?.sender || '',
          content: msg?.content || '',
          timestamp: Number(msg?.timestamp || 0)
        }));

        setMessages(transformedMessages);
        console.log('✅ Messages processed:', transformedMessages.length);

        // Scroll to bottom after loading messages
        setTimeout(scrollToBottom, 100);
      } catch (msgError) {
        console.warn('⚠️ Could not fetch messages:', msgError.message);
        // Set empty messages array if fetch fails
        setMessages([]);
      }

    } catch (err) {
      console.error('❌ Failed to fetch room data:', err);
      setError(err?.message || 'Failed to load room data');
    } finally {
      setLoading(false);
    }
  };

  /**
   * Handle sending a message (placeholder - implement with getContract)
   */
  const handleSendMessage = (e) => {
    e.preventDefault();
    if (newMessage.trim()) {
      alert('Message sending will be implemented with blockchain integration');
      // TODO: Implement with getContract() and contract.sendMessage()
      setNewMessage('');
    }
  };

  /**
   * Fetch room data on mount and when roomId changes
   */
  useEffect(() => {
    fetchRoomData();
  }, [roomId]);

  /**
   * Auto-scroll when messages change
   */
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  /**
   * Loading state
   */
  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center">
          <Loader className="w-8 h-8 text-primary-600 animate-spin mx-auto mb-4" />
          <p className="text-gray-600">Loading room from blockchain...</p>
        </div>
      </div>
    );
  }

  /**
   * Error state
   */
  if (error || !room) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center max-w-md">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <AlertCircle className="w-8 h-8 text-red-600" />
          </div>
          <h2 className="text-xl font-semibold text-gray-900 mb-2">
            {error || 'Room not found'}
          </h2>
          <p className="text-gray-600 mb-4">
            The room you're looking for doesn't exist or couldn't be loaded.
          </p>
          <Link to="/dashboard" className="btn-primary inline-flex items-center space-x-2">
            <ArrowLeft className="w-4 h-4" />
            <span>Back to Dashboard</span>
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      {/* Room Header */}
      <div className="bg-white border-b border-gray-200 px-6 py-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <Link
              to="/dashboard"
              className="p-2 hover:bg-gray-100 rounded-lg transition-colors duration-200"
            >
              <ArrowLeft className="w-5 h-5 text-gray-600" />
            </Link>
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 bg-primary-100 rounded-lg flex items-center justify-center">
                <Hash className="w-5 h-5 text-primary-600" />
              </div>
              <div>
                <div className="flex items-center space-x-2">
                  <h1 className="text-lg font-semibold text-gray-900">
                    {room?.name || 'Unnamed Room'}
                  </h1>
                  {room?.isPrivate ? (
                    <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded flex items-center space-x-1">
                      <Lock className="w-3 h-3" />
                      <span>Private</span>
                    </span>
                  ) : (
                    <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded flex items-center space-x-1">
                      <Globe className="w-3 h-3" />
                      <span>Public</span>
                    </span>
                  )}
                </div>
                <div className="flex items-center space-x-2 text-sm text-gray-500">
                  <Users className="w-4 h-4" />
                  <span>Room #{room?.id}</span>
                  <span>•</span>
                  <span>Created: {formatDate(room?.createdAt)}</span>
                  <span>•</span>
                  <span>Creator: {formatAddress(room?.creator)}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-gray-50">
        {messages?.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
              <Hash className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-medium text-gray-900 mb-2">No messages yet</h3>
            <p className="text-gray-600 text-sm">Be the first to send a message in this room!</p>
          </div>
        ) : (
          <>
            {messages.map((message) => (
              <div
                key={message?.id || Math.random()}
                className={`flex ${isOwnMessage(message?.sender) ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[70%] px-4 py-3 rounded-lg ${
                    isOwnMessage(message?.sender)
                      ? 'bg-primary-600 text-white'
                      : 'bg-white border border-gray-200'
                  }`}
                >
                  <div className="flex items-center justify-between mb-1">
                    <span className={`text-xs font-medium ${
                      isOwnMessage(message?.sender) ? 'text-primary-100' : 'text-gray-600'
                    }`}>
                      {isOwnMessage(message?.sender) ? 'You' : formatAddress(message?.sender)}
                    </span>
                    <span className={`text-xs ml-3 ${
                      isOwnMessage(message?.sender) ? 'text-primary-200' : 'text-gray-500'
                    }`}>
                      {formatTime(message?.timestamp)}
                    </span>
                  </div>
                  <p className="text-sm break-words whitespace-pre-wrap">
                    {message?.content || ''}
                  </p>
                </div>
              </div>
            ))}
            <div ref={messagesEndRef} />
          </>
        )}
      </div>

      {/* Message Input */}
      <div className="bg-white border-t border-gray-200 p-6">
        <form onSubmit={handleSendMessage} className="flex space-x-4">
          <input
            type="text"
            value={newMessage}
            onChange={(e) => setNewMessage(e.target.value)}
            placeholder="Type your message..."
            className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent"
            maxLength={500}
          />
          <button
            type="submit"
            disabled={!newMessage.trim()}
            className={`flex items-center space-x-2 px-6 py-2 rounded-lg font-medium transition-colors ${
              !newMessage.trim()
                ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                : 'bg-primary-600 hover:bg-primary-700 text-white'
            }`}
          >
            <Send className="w-4 h-4" />
            <span>Send</span>
          </button>
        </form>
        <p className="text-xs text-gray-500 mt-2">
          Messages are stored on the blockchain • {messages?.length || 0} messages in this room
        </p>
      </div>
    </div>
  );
};

export default ChatRoom;
